                        foodBar.style.width = data.food + '%';
                        foodValue.textContent = data.food + '%';
                        happinessBar.style.width = data.happiness + '%';
                        happinessValue.textContent = data.happiness + '%';

                        showMessage('Питомец покормлен! 🍎', 'success');
