        function getAntiForgeryToken() {
            const tokens = document.cookie.split(';')
                .map(c => c.trim())
                .filter(c => c.startsWith('.AspNetCore.Antiforgery.'))
                .map(c => c.split('=')[1]);

            return tokens.length > 0 ? tokens[0] : '';
